//! Generated model types (F.24).
//!
//! This module includes the Rust structs generated by `build.rs` from the
//! Fluxer OpenAPI spec (`core/openapi.json`) via `typify-impl`. The generated
//! types live in `$OUT_DIR/types.rs` at compile time.
//!
//! The spec uses `*Response` / `*ResponseSchema` / `*Request` suffixes; the
//! rest of the crate expects bare names (`User`, `Guild`, `Channel`, …). The
//! type aliases below map the spec names to the bare names used throughout
//! `fluxer`. The hand-written `http.rs` + `ratelimit.rs` transport is kept
//! (the locked hybrid decision); these generated types replace the
//! hand-written `crate::models` structs.
//!
//! `Snowflake` is preserved as a `String` alias (BigInt-safe contract).

pub use generated_inner::*;

#[allow(unused_imports)]
mod generated_inner {
    // The build script writes the generated types here.
    include!(concat!(env!("OUT_DIR"), "/types.rs"));
}

// ---------------------------------------------------------------------------
// Bare-name aliases (spec name -> crate name).
//
// The generated code uses the spec's `*Response` / `*ResponseSchema` names.
// The rest of the crate refers to these by their bare names, so re-export
// them under aliases. `Snowflake` stays a `String` alias.
// ---------------------------------------------------------------------------

/// A Fluxer snowflake identifier. Newtyped for clarity; serialized as a string.
/// The spec models this as `SnowflakeType` (a string with a pattern); we keep
/// the `Snowflake = String` alias for source compatibility.
pub type Snowflake = String;

pub type User = UserPartialResponse;
pub type UserPrivate = UserPrivateResponse;
pub type Guild = GuildResponse;
pub type Channel = ChannelResponse;
pub type Member = GuildMemberResponse;
pub type Role = GuildRoleResponse;
pub type Emoji = GuildEmojiResponse;
pub type Message = MessageResponseSchema;
pub type Reaction = MessageReactionResponse;
pub type Attachment = MessageAttachmentResponse;
pub type ReadState = ReadStateResponse;
pub type Invite = InviteResponseSchema;
pub type Relationship = RelationshipResponse;
pub type GatewayBot = GatewayBotResponse;
pub type GuildBan = GuildBanResponse;
pub type PermissionOverwrite = ChannelOverwriteResponse;